3_real_world_example.code:
let currentController = null;

async function downloadLargeFile() {
  // 1. Create a new controller for this request
  currentController = new AbortController();

  try {
    console.log('Download started...');
    // 2. Attach the signal to the fetch
    const response = await fetch('/api/massive-file', {
      signal: currentController.signal
    });
    const data = await response.json();
    console.log('Download complete!');

  } catch (err) {
    // 3. Handle the explicit cancellation
    if (err.name === 'AbortError') {
      console.log('Download was manually cancelled by the user.');
    } else {
      console.error('Download failed due to a network error.', err);
    }
  }
}

// Simulated 'Cancel' button click
function onCancelClick() {
  if (currentController) {
    currentController.abort(); // Yanks the string, killing the fetch instantly
  }
}

